  ('elementary-0489de64-moex-00001', 'elementary-0489de64', 'elementary-0489de64-moex-114-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '下列有關航業法國際聯營組織及國際航運協議之敘述何者正確？', '["船舶運送業參加國際聯營組織，可向航政機關備查即可", "聯營組織變更或解散時，同樣只須向航政機關備查即可", "聯營組織運價表應容許船舶運送業自由決定其運費、票價", "國際聯營組織之運費、票價不須申請航政機關備查"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "c174667e9ba2", "answer_pdf_sha1": "f5f14ba1000c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00002', 'elementary-0489de64', 'elementary-0489de64-moex-114-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '受船舶運送業之委託代為處理船舶客貨運送及其有關業務而受報酬為營業之事業稱為：', '["船舶運送業", "船務代理業", "海運承攬運送業", "貨櫃集散站經營業"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "c174667e9ba2", "answer_pdf_sha1": "f5f14ba1000c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00003', 'elementary-0489de64', 'elementary-0489de64-moex-114-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '下列關於交通部航港局之沿革與執掌工作項目敘述何者錯誤？', '["臺灣港務公司之成立係參照國際先進海運國家「政企分離」之商港管理作法", "目前已推動參與國際海事組織（IMO）稽核機制", "成立通用無障礙海運環境推動小組，係為推動及改善旅客無障礙環境", "東部航務中心包括蘇澳與花蓮兩處國際商港"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "c174667e9ba2", "answer_pdf_sha1": "f5f14ba1000c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00004', 'elementary-0489de64', 'elementary-0489de64-moex-114-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '下列有關國內線航班依法提供之優待票敘述何者正確？', '["年滿2歲（含）且未滿12歲之旅客享六折優惠", "敬老票適用對象除本國籍年滿65歲之旅客外，亦包含符合馬偕計畫之外籍人士", "愛心陪同票適用對象限持有身心障礙手冊之同行陪伴者，其中一人可享七五折優惠", "離島居民票適用對象限設籍於金門、澎湖、馬祖地區之居民，可享六折優惠"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "c174667e9ba2", "answer_pdf_sha1": "f5f14ba1000c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00005', 'elementary-0489de64', 'elementary-0489de64-moex-114-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '鐵路法之高速鐵路係指列車營運速度，經許可達每小時多少公里以上之鐵路？', '["200公里", "300公里", "250公里", "180公里"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "c174667e9ba2", "answer_pdf_sha1": "f5f14ba1000c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00006', 'elementary-0489de64', 'elementary-0489de64-moex-114-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '都市計畫停車場用地以多目標使用方式，經主管機關或鄉鎮市公所將土地出租民間興建經營稱為：', '["BOT", "OT", "BOO", "BTO"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "c174667e9ba2", "answer_pdf_sha1": "f5f14ba1000c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00007', 'elementary-0489de64', 'elementary-0489de64-moex-114-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '下列有關停車場法規範停車場之敘述何者錯誤？', '["臨時路外停車場設置於住宅區者，應符合住宅區建蔽率、容積率及建築高度之規定", "臨時路外停車場在核定使用期間，不受都市計畫法令土地使用分區管制有關建蔽率與容積率之限制", "鄰接禁止停車區路段有劃設路邊停車場之必要時，得以計時或計次收費", "都市計畫停車場用地投資興建之停車場於使用年限屆滿後，應無償歸屬於主管機關或鄉鎮市公所所有"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "c174667e9ba2", "answer_pdf_sha1": "f5f14ba1000c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00008', 'elementary-0489de64', 'elementary-0489de64-moex-114-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '我國尚未裝設儀器降落系統之機場為何？', '["馬公機場", "金門尚義機場", "南竿機場", "嘉義機場"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "c174667e9ba2", "answer_pdf_sha1": "f5f14ba1000c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00009', 'elementary-0489de64', 'elementary-0489de64-moex-114-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '下列有關航空器在軍用機場降落之敘述何者正確？', '["航空器如須在軍用飛行場降落，應逕行向軍事航空管理機構申請核准", "航空器如因故緊急降落者，仍須事先申請核准", "外國籍私人包機不得申請於軍用飛行場降落", "航空器在軍用飛行場起降，應遵照該飛行場之規定，並聽從其指揮"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "c174667e9ba2", "answer_pdf_sha1": "f5f14ba1000c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00010', 'elementary-0489de64', 'elementary-0489de64-moex-114-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '民用航空法用詞定義何者錯誤？', '["航空站係指具備供航空器載卸客貨之設施與裝備及用於航空器起降活動之區域", "航空器係指任何藉空氣對地球表面之反作用力，得以飛航於大氣中之器物", "航路係指經民用航空局指定於空中以通道形式設立之管制空域", "飛行場係指用於航空器起降活動之水上與陸上區域"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "c174667e9ba2", "answer_pdf_sha1": "f5f14ba1000c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL)
